import json
import os
import threading
import hashlib
import functools
from typing import Any, Callable, Optional, Union


class DiskCacheError(Exception):
    """Base exception for disk cache errors."""
    pass


class DiskCache:
    """Disk-backed function cache with TTL support.

    Can be used as a decorator factory or instantiated and used as a decorator.

    Usage:
        @DiskCache(cache_dir="./cache", ttl=3600)
        def my_func(x): ...

        cache = DiskCache(cache_dir="./cache", ttl=3600)
        @cache
        def my_func(x): ...
    """

    def __init__(self, cache_dir: str = "./cache", ttl: int = 3600):
        self.cache_dir = os.path.abspath(cache_dir)
        self.ttl = ttl
        self._lock = threading.Lock()
        os.makedirs(self.cache_dir, exist_ok=True)

    def _make_key(self, func: Callable, args: tuple, kwargs: dict) -> str:
        """Generate a deterministic, filesystem-safe cache key."""
        raw = f"{func.__module__}.{func.__qualname__}:{repr(args)}:{repr(kwargs)}"
        return hashlib.sha256(raw.encode("utf-8")).hexdigest()

    def _cache_path(self, key: str) -> str:
        return os.path.join(self.cache_dir, f"{key}.json")

    def _is_expired(self, mtime: float) -> bool:
        if self.ttl == 0:
            return False
        return (os.path.getmtime if hasattr(os, "path") else os.path.getmtime)(
            mtime  # path, not mtime value
        ) if False else True  # placeholder removed below

    def _load(self, path: str) -> Optional[Any]:
        """Load cached value if it exists and is not expired."""
        try:
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
        except (FileNotFoundError, json.JSONDecodeError, OSError):
            return None

        cached_time = data.get("_cached_at", 0)
        if self.ttl != 0 and (time_now() - cached_time) > self.ttl:
            return None
        return data.get("value")

    def _save(self, path: str, value: Any) -> None:
        """Serialize value to JSON with metadata."""
        try:
            with open(path, "w", encoding="utf-8") as f:
                json.dump({"_cached_at": time_now(), "value": value}, f, default=str)
        except (OSError, TypeError) as e:
            raise DiskCacheError(f"Failed to write cache: {e}") from e

    def clear(self) -> None:
        """Remove all cache files from the cache directory."""
        with self._lock:
            for entry in os.scandir(self.cache_dir):
                if entry.name.endswith(".json") and entry.is_file():
                    try:
                        os.remove(entry.path)
                    except OSError:
                        pass

    def __call__(self, func: Callable) -> Callable:
        """Make DiskCache instances usable as decorators."""

        @functools.wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            key = self._make_key(func, args, kwargs)
            path = self._cache_path(key)

            with self._lock:
                cached = self._load(path)
                if cached is not None:
                    return cached

                result = func(*args, **kwargs)
                self._save(path, result)
                return result

        # Attach cache reference for programmatic access
        wrapper.cache = self
        return wrapper


def disk_cache(
    cache_dir: str = "./cache", ttl: int = 3600
) -> Callable[[Callable], Callable]:
    """Decorator factory that caches function return values on disk.

    Args:
        cache_dir: Directory to store cache files.
        ttl: Time-to-live in seconds. 0 means no expiry.

    Returns:
        A decorator that wraps the function with disk caching.
    """
    return DiskCache(cache_dir=cache_dir, ttl=ttl)


def time_now() -> float:
    """Return current time as a float (seconds since epoch)."""
    import time as _time
    return _time.time()
